def merge_cells(data):
    if not data or not isinstance(data, list):
        return []

    merged_data = []
    previous_value = None
    merged_row = []

    for row in data:
        if not isinstance(row, list):
            continue

        new_row = []
        for value in row:
            if value == previous_value:
                new_row.append("")  # Keep the cell empty if it's a duplicate
            else:
                new_row.append(value)
                previous_value = value
        merged_data.append(new_row)
        previous_value = None  # Reset for the next row

    return merged_data

def solve(data):
    return merge_cells(data)
